// PATCH [OPENCLAW_IPV4_ONLY]: respect explicit bind mode — only alias ::1 for default
// 'loopback' mode. Custom (and other) bind modes bind exactly what the user asked for.
// Env var OPENCLAW_GATEWAY_BIND_ALIAS_IPV6=0 forces IPv4-only regardless of mode.
async function resolveGatewayListenHosts(bindHost, opts) {
	if (bindHost !== "127.0.0.1") return [bindHost];
	if (process.platform === "win32") return [bindHost];
	if (process.env?.OPENCLAW_GATEWAY_BIND_ALIAS_IPV6 === "0") return [bindHost];
	const bindMode = opts?.bindMode;
	if (bindMode && bindMode !== "loopback") return [bindHost];
	if (await (opts?.canBindToHost ?? canBindToHost)("::1")) return [bindHost, "::1"];
	return [bindHost];
}
/**
* Validate if a string is a valid IPv4 address.
*
* @param host - The string to validate
* @returns True if valid IPv4 format
*/

